=Article title: {{ $json.src_title || '' }}
Summary: {{ $json.short_summary || '' }}
Publication date (UTC): {{ $json.src_published_at || '' }}
Source URL: {{ $json.src_url || '' }}

Task:
Find the exact water body location (sea/strait/bay) where this spill occurred.
Use web search; if possible, confirm against NOAA IncidentNews.
Return ONLY one JSON object in ```json ...``` as specified above.

parameters.jsCode:
const item = $input.first().json;

let rawContent = item?.message?.content;

if (!rawContent && item?.choices?.[0]?.message?.content) {
  rawContent = item.choices[0].message.content;
}

rawContent = (rawContent || '').toString();

function extractJSONBlock(str) {
  if (!str) return null;

  const fence = /```json\s*([\s\S]*?)\s*```/i;
  const m = str.match(fence);
  if (m && m[1]) return m[1];

  const brace = /{[\s\S]*}/m;
  const m2 = str.match(brace);
  return m2 ? m2[0] : null;
}

let obj = {};
try {
  const jsonPart = extractJSONBlock(rawContent);
  if (!jsonPart) {
    throw new Error('No JSON block found in LLM content');
  }
  obj = JSON.parse(jsonPart);
} catch (e) {
  const baseEvent = $items('PG.SELECT_EVENT_S1')[0].json;
  return [{
    json: {
      ev_id: baseEvent.id,
      parse_error: String(e),
      raw_content: rawContent
    }
  }];
}

function numOrNull(v) {
  if (v === null || v === undefined) return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

let lat = numOrNull(obj.lat);
let lon = numOrNull(obj.lon);

if (lat !== null && (lat < -90 || lat > 90)) lat = null;
if (lon !== null && (lon < -180 || lon > 180)) lon = null;

const fix5 = v => v === null ? null : Number(v.toFixed(5));
lat = fix5(lat);
lon = fix5(lon);

const baseEvent = $items('PG.SELECT_EVENT_S1')[0].json;

return [{
  json: {
    ev_id: baseEvent.id,
    canonical_place: obj.canonical_place ?? null,
    lat,
    lon,
    confidence: obj.confidence ?? null,
    notes: obj.notes ?? null,
    evidence: Array.isArray(obj.sources) ? obj.sources.slice(0,5) : null
  }
}];

parameters.query:
=UPDATE public.events
SET lat = {{ $json.lat !== null ? $json.lat : 'NULL' }},
    lon = {{ $json.lon !== null ? $json.lon : 'NULL' }}
WHERE id = {{ $json.ev_id }}
RETURNING id AS ev_id, lat, lon;

parameters.jsCode:
const upd = $input.first().json;

const baseEvent = $items('PG.SELECT_EVENT_S1')[0].json;

return [{
  json: {
    event_id: upd.ev_id || baseEvent.id,
    lat: upd.lat ?? baseEvent.lat,
    lon: upd.lon ?? baseEvent.lon,
    updated: !!upd.ev_id
  }
}];

